def solve(*args):
    if not args or len(args) < 2:
        return None

    user_role = args[0]
    reviews = args[1]

    if user_role not in ['admin', 'reviewer', 'user']:
        return None

    pending_reviews = [review for review in reviews if review['status'] == 'pending']

    if user_role == 'admin':
        return pending_reviews

    if user_role == 'reviewer':
        return [review for review in pending_reviews if review['assigned_to'] == 'reviewer']

    if user_role == 'user':
        return [review for review in pending_reviews if review['created_by'] == 'user']

    return None
